class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        set<string> result;
        queue<string> q;
        q.push(s);
        unordered_set<string> visited{s};
        while (!q.empty()) {
            string curr = q.front();
            q.pop();
            if (isValid(curr)) {
                result.insert(curr);
                continue;
            }
            for (int i = 0; i < curr.size(); ++i) {
                if (curr[i] == '(' || curr[i] == ')') {
                    string next = curr.substr(0, i) + curr.substr(i + 1);
                    if (visited.find(next) == visited.end()) {
                        q.push(next);
                        visited.insert(next);
                    }
                }
            }
        }
        return vector<string>(result.begin(), result.end());
    }
    bool isValid(string s) {
        int count = 0;
        for (char c : s) {
            if (c == '(') {
                count++;
            } else if (c == ')') {
                count--;
            }
            if (count < 0) {
                return false;
            }
        }
        return count == 0;
    }
};
